INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'de7f47ca-209e-4ecb-87b5-b400f008863b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ansible Collections — Reusable Modules, Galaxy Registry, and Versioning Strategy$escape$,
  $escape$Ansible Collections (introduced in 2.9, mandatory post-2.10) are the canonical unit for distributing reusable modules, roles, and plugins. A collection lives under `collections/ansible_collections/<namespace>/<name>/` and is declared in `galaxy.yml` with a semantic version. Publish to Ansible Galaxy or a private Automation Hub using `ansible-galaxy collection build` then `ansible-galaxy collection publish`. Pin dependencies in `requirements.yml` using exact (`==1.4.2`) or constrained (`>=1.4,<2.0`) version ranges — never omit the version pin in production, since Galaxy collections are mutable by default. For air-gapped environments, build a `.tar.gz` artifact in CI and install offline with `ansible-galaxy collection install ./ns-name-1.4.2.tar.gz`. Inside your collection, prefix custom modules under `plugins/modules/` and document them with `DOCUMENTATION`, `EXAMPLES`, and `RETURN` YAML blocks so `ansible-doc` works out of the box. Use `meta/runtime.yml` to declare the minimum `requires_ansible` version — this prevents silent breakage when consumers run older Ansible cores.$escape$,
  $escape$# requirements.yml — pin collections for reproducible installs
collections:
  - name: community.general
    version: ">=8.0.0,<9.0.0"
  - name: amazon.aws
    version: "==7.4.0"
  - name: myorg.platform
    source: https://automation-hub.internal/api/galaxy/
    version: "==2.1.3"

# Install pinned collections
# ansible-galaxy collection install -r requirements.yml -p ./collections

# Build and publish your own collection
# ansible-galaxy collection build collections/ansible_collections/myorg/platform
# ansible-galaxy collection publish myorg-platform-2.1.3.tar.gz --server automation_hub$escape$,
  $escape$bash$escape$,
