INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6687da81-e229-4024-a0d4-c48fa6bd16fa',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ansible IaC Testing — Molecule, Checkov, and ansible-lint as Policy Gates$escape$,
  $escape$Ansible roles aren't exempt from IaC quality gates. Three tools cover the full testing pyramid. Molecule handles integration testing: it spins up ephemeral Docker or Podman containers, converges your role, then runs `verify.yml` assertions using the `ansible.builtin.assert` module against actual system state — not mocked state. For static security analysis, Checkov natively scans Ansible playbooks and flags issues like `become: yes` without explicit `become_user`, world-writable file modes, or hardcoded secrets in `vars:` blocks. Run it in CI with `checkov -d . --framework ansible --compact`. ansible-lint fills the policy-as-code role: write custom rules in Python under `rules/` that enforce org-wide conventions — required tags, forbidden modules, naming patterns. Set `warn_list` vs `error_list` in `.ansible-lint` to control gate severity. The enforcement hierarchy is: lint (fast, pre-commit) → checkov (security, PR gate) → Molecule (integration, merge gate). Skipping Molecule on role changes that touch `handlers/` or `defaults/` is a common source of silent regressions.$escape$,
  $escape$# .ansible-lint
profile: production
error_list:
  - yaml[truthy]
  - no-free-form
  - risky-file-permissions
warn_list:
  - experimental

# rules/RequireTagsRule.py
from ansiblelint.rules import AnsibleLintRule

class RequireTagsRule(AnsibleLintRule):
    id = "LOCAL001"
    description = "All tasks must define at least one tag"
    severity = "HIGH"

    def matchtask(self, task, file=None):
        return not task.get("tags")$escape$,
  $escape$python$escape$,
