INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a1802f6b-154f-4a52-ac5b-735d263f1497',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ansible Destroy Safety — Preventing Accidental Resource Deletion with Lifecycle Guards$escape$,
  $escape$Ansible has no native `prevent_destroy` like Terraform, so destruction safety must be built deliberately. The first line of defense is `--check` mode combined with `--diff`, which dry-runs playbooks and shows what would change without applying it. For critical infrastructure, gate destructive tasks behind a `when` condition tied to an explicit variable: `when: allow_destroy | default(false)`. This forces callers to pass `-e allow_destroy=true` consciously, making accidents loud. Use `block` with `rescue` to catch failures on deletion tasks and emit alerts before re-raising. For cloud resources managed via `amazon.aws` or `azure.azcollection`, set `termination_protection: true` on the resource itself — Ansible will respect the provider's API rejection. Pair this with `tags` filtering: mark destructive plays with `tags: [destructive]` and exclude them in CI pipelines using `--skip-tags destructive`. Finally, use `assert` tasks at playbook entry to validate environment name, preventing prod teardowns triggered from wrong inventory groups.$escape$,
  $escape$- name: Guard destructive teardown
  hosts: all
  vars:
    allow_destroy: false
  tasks:
    - name: Abort if destroy not explicitly enabled
      assert:
        that:
          - allow_destroy | bool
          - target_env != 'production'
        fail_msg: "Destroy blocked. Pass -e allow_destroy=true and target non-prod."
      tags: [destructive]

    - name: Terminate EC2 instance
      amazon.aws.ec2_instance:
        instance_ids: "{{ instance_id }}"
        state: absent
      when: allow_destroy | bool
      tags: [destructive]$escape$,
  $escape$bash$escape$,
