INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4f9e2d11-0459-4f87-9c87-5304e231b53d',
  '00000000-0000-0000-0000-000000000001',
  $escape$Ansible Cost Gates — Blocking Deploys with Infracost Before Apply$escape$,
  $escape$Infracost doesn't parse Ansible's imperative resource tasks — it targets Terraform HCL. But Ansible is often the orchestration layer that *calls* Terraform, making it the right place to enforce cost gates. Use `ansible.builtin.command` to invoke `infracost breakdown --format json` against your Terraform directory, `register` stdout, then pipe through `from_json` to extract `totalMonthlyCost`. A downstream `ansible.builtin.assert` task aborts the entire play if projected spend exceeds a threshold — zero cloud resources touched, zero surprise bills.

Define `cost_threshold` in `group_vars/all.yml` so limits are environment-scoped: `$50` for dev, `$500` for prod. Drop the check into a `pre_tasks` block in your provisioning playbook so it runs before any `community.aws.*` or `azure.azcollection.*` tasks fire. For change detection, run `infracost diff --compare-to baseline.json` and assert the monthly delta is within an acceptable range before allowing scale-up plays to proceed. This turns Ansible from a blind executor into a cost-aware provisioning controller.$escape$,
  $escape$- name: Estimate infrastructure cost
  ansible.builtin.command:
    cmd: infracost breakdown --path ./terraform --format json
    chdir: "{{ playbook_dir }}"
  register: infracost_result
  changed_when: false

- name: Extract monthly cost
  ansible.builtin.set_fact:
    monthly_cost: "{{ (infracost_result.stdout | from_json).totalMonthlyCost | float }}"

- name: Gate on cost threshold
  ansible.builtin.assert:
    that:
      - monthly_cost <= cost_threshold | float
    fail_msg: >-
      Estimated ${{ monthly_cost }}/mo exceeds threshold ${{ cost_threshold }}/mo.
      Aborting provisioning play.
  vars:
    cost_threshold: "{{ env_cost_limit | default(200.0) }}"$escape$,
  $escape$bash$escape$,
